solution_code:
#include <iostream>

int main() {
    char word[50]{};
    std::cin >> word;

    int vowelCount = 0;
    for (const char* p = word; *p != '\0'; ++p) {
        char c = *p;
        if (c == 'a' || c == 'e' || c == 'i' || c == 'o' || c == 'u')
            ++vowelCount;
    }

    std::cout << "Vowels: " << vowelCount << '\n';
    return 0;
}

