solution_code:
#include <iostream>

int cstrLen(const char* s) {
    int len = 0;
    while (*s != '\0') {
        ++len;
        ++s;
    }
    return len;
}

int main() {
    char word[50]{};
    std::cin >> word;
    std::cout << "Length: " << cstrLen(word) << '\n';
    return 0;
}
